import sys
input = sys.stdin.readline

def solve():
    n = int(input())
    a = list(map(int, input().split()))

    # dp: dict l -> min r
    dp = {0: 0}

    for d in a:
        new_dp = {}
        for l, r in dp.items():
            # go right
            nl, nr = l + d, max(r - d, 0)
            if nl not in new_dp or new_dp[nl] > nr:
                new_dp[nl] = nr
            # go left
            if l >= d:
                nl, nr = l - d, r + d
            else:
                nl, nr = 0, r + d
            if nl not in new_dp or new_dp[nl] > nr:
                new_dp[nl] = nr
        dp = new_dp

    return min(l + r for l, r in dp.items())

